VALUES
  ('promotion-d0d1b9a2-moex-00133', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-f6c431ec', 'sub-promotion-d0d1b9a2-03', NULL, 'single_choice', '若某地區課徵的不動產稅負產生租稅資本化，則該地不動產的價格會有何變化？', '["降低", "不變", "提高", "無法確定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "4f574ff3f066", "answer_pdf_sha1": "2f452a3b06f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00134', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-f6c431ec', 'sub-promotion-d0d1b9a2-03', NULL, 'single_choice', '關於有條件無配合款與無條件等兩種補助方式，對於提升受補助地區福利水準的差異，下列敘述 何者正確？', '["前者較高", "後者較高", "後者不低於前者", "前者不低於後者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "4f574ff3f066", "answer_pdf_sha1": "2f452a3b06f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00135', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-f6c431ec', 'sub-promotion-d0d1b9a2-03', NULL, 'single_choice', '在簡單IS與LM模型下，比較公債融通與貨幣融通之產出效果，對所得之影響為何？', '["公債融通影響較小", "貨幣融通影響較小", "二者之影響相同", "二者均無影響"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "4f574ff3f066", "answer_pdf_sha1": "2f452a3b06f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00136', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '甲公司 X1 年 1 月 1 日以$80,000,000 取得乙公司流通在外股數 2,000,000 股，乙公司總股數為 10,000,000股，而乙公司淨資產為$240,000,000。收購價格高於乙公司之淨資產為商譽。乙公司X1 年之稅後淨利為$100,000,000，X1年底發放股利之金額為$8,000,000。試問，X1年甲公司對乙公 司之投資收益為何？', '["$20,000,000", "$18,000,000", "$18,400,000", "$48,000,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "8b25447706f5", "answer_pdf_sha1": "ed2279a94aa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00137', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '甲公司與客戶簽訂合約，將X、Y與Z三項商品以$900之包裹價格出售。惟甲公司經常個別單獨 銷售X、Y與Z三項商品，因此，X、Y與Z三項商品的單獨售價可直接觀察而得。另外，因為 Y商品與Z商品在功能上互補的關係，若同時購買Y商品與Z商品時，甲公司的銷售價則為$400。 若就個別商品單獨報價的話，X 商品為$500、Y 商品為$300 而 Z 商品則為$200。假設甲公司於 X1年7月1日移交X商品給客戶，而剩餘的Y商品與Z商品則於X1年8月1日移交，且甲公 司於X1年8月31日收到所有的貨款。試問，此交易中，甲公司從其所銷售之Z商品認列的銷貨 收入金額為何？', '["$400", "$360", "$240", "$160"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "8b25447706f5", "answer_pdf_sha1": "ed2279a94aa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00138', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '甲公司X1年6月底所編製之銀行往來調節表之明細如下：公司帳面餘額$15,600，銀行對帳單餘 額$13,840，銀行發放之利息$120公司並未入帳，銀行代扣之手續費$1,200公司並未入帳，在途存 款$6,240，另有未兌現支票一張。試問，該未兌現支票之金額為何？', '["$5,560", "$5,440", "$4,240", "$8,040"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "8b25447706f5", "answer_pdf_sha1": "ed2279a94aa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00139', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年1月1日以$500,000購入一批肉牛。X1年間共購入牧草$125,000用以飼養肉牛， 所僱用之飼養人員之X1年間薪資總額為$75,000。X1年12月31日，甲公司所飼養之肉牛之公 允價值上升至$980,000，出售成本為$30,000。這批肉牛於甲公司X1年12月31日之資產負債表 中之帳面金額為何？', '["$700,000", "$1,180,000", "$670,000", "$950,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "8b25447706f5", "answer_pdf_sha1": "ed2279a94aa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00140', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '甲公司之自動化生產機台於 X1 年 12 月 31 日有減損跡象。該機器成本$500,000，累計折舊 $100,000，公允價值減出售成本為$240,000，使用價值$350,000。甲公司決定繼續使用該機器，且 不改變其原始估計之殘值（原始估計殘值為零），以及10年的耐用年限（甲公司之機台於X0年 1月1日達到可供使用狀態）。甲公司於X1年12月31日辦理減損相關的會計處理，並繼續以直 線法折舊該機台。X2 年 12 月 31 日因機台使用方式發生重大變故，甲公司再次對該機台評估相 關價值，發現公允價值減出售成本為$300,000，使用價值為$400,000。假設甲公司未曾對該機台辦 理過重估價，試問該機台於X2年12月31日認列於甲公司資產負債表中的帳面價值為何？', '["$400,000", "$350,000", "$300,000", "$240,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "8b25447706f5", "answer_pdf_sha1": "ed2279a94aa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00141', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '下列為甲公司於X1年設立後各年度之會計利潤(損失)與稅率之資料：X1年$150,000（稅率25%）， X2年$270,000（稅率25%），X3年$55,000（稅率20%），X4年$40,000（稅率17%），X5年($700,000) （稅率25%），X6年$100,000（稅率20%），且各年度皆無暫時性差異與永久性差異。假設甲公司 選擇損失可先扣抵以前5年再扣抵以後10年之所得，且於X5年時預估未來課稅所得很有可能供 未使用課稅損失（虧損扣抵）使用。試問，以下何者為X5年甲公司可能發生之交易？', '["借記所得稅費用$20,000", "借記本期所得稅資產$122,800", "借記所得稅利益$37,000", "貸記遞延所得稅資產$37,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "8b25447706f5", "answer_pdf_sha1": "ed2279a94aa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00142', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '甲公司之退職後福利計畫為確定福利計畫。甲公司之計畫資產之公允價值於X1年12月31日與 X2年12月31日各為$200,000及$240,000。甲公司於X2年年底提撥$40,000至員工之退職後福 利基金，並貸記淨確定福利負債$60,000，期末之確定福利支出給付為$30,000。甲公司之福利計畫 之當期服務成本為利息成本之 1.5 倍，假設利息成本於 X2 年年底發生時，利息成本為前期服務 成本之6倍。甲公司並假設X2年精算假設之各條件未改變時，則預期報酬將等於實際報酬。試 問，甲公司計畫資產之實際報酬率為何？', '["30%", "20%", "15%", "12.5%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "8b25447706f5", "answer_pdf_sha1": "ed2279a94aa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL)
